prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Find message flows and their source/target references
SELECT ?msgFlow ?sourceRef ?targetRef ?messageRef WHERE {
  ?msgFlow a bboExt:MessageFlow .
  OPTIONAL { ?msgFlow bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?targetRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?messageRef . }
  ?msgFlow tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_c4417a54_a50e_4ff3_83f7_0ffc13671109> .
}
LIMIT 30

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Find ChoreographyTasks and their initiatingParticipantRef to link participants to tasks
SELECT ?task ?taskName ?initPartRef WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_c4417a54_a50e_4ff3_83f7_0ffc13671109> .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:initiatingParticipantRef ?initPartRef . }
}
LIMIT 30

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Let me trace the path from EventBasedGateway to understand the flow
# EventBasedGateway is sid-D7738C6D-63A4-4D42-BCC4-47597AC64A74
SELECT ?sourceName ?targetName WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge bbo:has_sourceRef ?source .
  ?edge bbo:has_targetRef ?target .
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
  VALUES ?source { 
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-D7738C6D-63A4-4D42-BCC4-47597AC64A74>
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-F9E200DB-7A4D-418C-BAE0-3F93D88763E8>
  }
}
